[FormDataSourceEventHandler(formDataSourceStr(SalesTable, SalesTable), FormDataSourceEventType::Activated)]
public static void SalesTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();

    FormStringControl placeOfLoading   = formRun.design().controlName(formControlStr(SalesTable, PlaceOfLoading));
    FormStringControl placeOfDischarge = formRun.design().controlName(formControlStr(SalesTable, PlaceOfDischarge));

    if (ETG_Parameters::find().ValidatePortOfDischargeField == NoYes::Yes)
    {
        placeOfDischarge.mandatory(true);
    }
    if (ETG_Parameters::find().ValidatePortOfLoadingField == NoYes::Yes)
    {
        placeOfLoading.mandatory(true);
    }
}

[FormDataSourceEventHandler(formDataSourceStr(SalesTable, SalesTable), FormDataSourceEventType::ValidatingWrite)]
public static void SalesTable_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    ETGSalesTableFormEventHandler::validatePorts(sender.formRun(), e);
}

